* draw_climb_scenery_back — wall-top posts drawn BEFORE the Fuji, so the
*   mountain occludes their upper rows (oracle order: AA31 -> Fuji -> ...).
* table entry = fdb cel ; fdb plc_ptr (§2F: placement value lives ONCE in plc_<id>).
