        ldy     #climb_scn_back_tbl
dcsb_loop:
        ldx     ,y++                    ; X = cel ptr (0 = end)
        beq     dcsb_done
        ldu     ,y++                    ; U -> plc_ row (col,sub,row) — §2F single home
